							function IsComplete()
{  
	return true;                  
}

					EVA.AddPlantilla = function(MyOBJ)
{                
	this.Plantillas["K_"+MyOBJ.Id]=MyOBJ;
}

EVA.GetPlantilla = function(Id)
{                
	return this.Plantillas["K_"+Id];
}

function compare(V1, V2)
{
	var DIF=V2-V1;
	if (DIF==0) return 0;
	if (Math.abs(DIF)==DIF) return -1;

	return 1;
}

function Replace(strin, strfnd, strrpl) 
{
	return strin.replace(new RegExp(strfnd, "ig"), strrpl);
}   

function REFRESH()
{ 
	var key, MyPLA;				

	/////////////////////////////////////////////////////
  //Realizando los Calculos individuales   
	for(key in EVA.Plantillas)
	{                 
		MyPLA=EVA.Plantillas[key];
		MyPLA.RECALC();
	}

	/////////////////////////////////////////////////////
	//Calculando Totales
	EVA.Value   =0.0;
	EVA.MaxValue=0.0;

	for(key in EVA.Plantillas)
	{
		MyPLA=EVA.Plantillas[key];
		if (!MyPLA.MostrarResumen) continue;

		//Calculo del Valores
		if (MyPLA.Value==null || EVA.Value==null)
		{              
			EVA.Value=null;
		} else
		{
			EVA.MaxValue+=MyPLA.Pond; 
			EVA.Value   +=MyPLA.Pond*MyPLA.Value/MyPLA.MaxValue;
		}
	} 
	EVA.Value=(EVA.Value==null?null:EVA.Value/EVA.MaxValue)

	/////////////////////////////////////////////////////
  //Actualizar HTML   
	for(key in EVA.Plantillas)
	{                              
		MyPLA=EVA.Plantillas[key];
		MyPLA.REFRESH();
	}

}

function DDOCHANGE(DDOEVA)
{
	var key, MyPLA;				

	DDOEVA.SetAttr("nmd-status","~u,");         

	/////////////////////////////////////////////////////
  //Realizando los Calculos individuales   
	for(key in EVA.Plantillas)
	{
		MyPLA=EVA.Plantillas[key];
		MyPLA.DDOCHANGE(DDOEVA, DDOEVA.FindElement("PLANTILLAS").FindElement2("PLANTILLA","ID",MyPLA.Id));
	}

	DDOEVA.SetAttr("n_resultado", (EVA.Value==null?"":EVA.Value*EVA.MaxEscala)); 
}

//funcion carmen
function textAreaAdjust(o) 
{                            
  o.style.height = o.scrollHeight + "px";
}

