					PLA.Items=new Array();
PLA.AddItem = function(MyItem)
{        
	PLA.Items["K_"+MyItem.Id]=MyItem;
}

PLA.RECALC = function()
{                
	var key, MyITEM, t;   

	this.Value=0.0;
	this.MaxValue=0.0;

	//Recorro los ITEMS
	for (key in this.Items)
	{
		MyITEM=this.Items[key];
		MyITEM.CtrlList=document.getElementsByName("O_"+MyITEM.Id);

		//Valor
		MyITEM.Value=null;
		for(t=0; t!=MyITEM.CtrlList.length; t++)
			if (MyITEM.CtrlList.item(t).checked) 
				MyITEM.Value=parseFloat(MyITEM.CtrlList.item(t).value) / this.MaxEscala;

		//Totales      
		if (this.Value==null || MyITEM.Value==null)
		{
			this.Value   =null;                      
		} else
		{
			this.MaxValue+=MyITEM.Pond;
			this.Value   +=MyITEM.Pond*MyITEM.Value;
		}
	}           
}

PLA.REFRESH = function()
{
	var CELD;

	CELD=document.getElementById("T_"+this.Id);
	CELD.innerHTML=(this.Value==null?"":Math.round(100*this.Value/this.MaxValue)+"%");
}

PLA.DDOCHANGE = function(DDOEVA, DDOPLA)
{
	var key, MyITEM, DDOITEM;   

	DDOPLA.SetAttr("nmd-status" , "~u,");
	DDOPLA.SetAttr("n_resultado", this.Value==null?"":(this.Value*this.MaxEscala/this.MaxValue));

 	for (key in this.Items)
 	{                      
 		MyITEM=this.Items[key];

		DDOITEM=DDOPLA.FindElement("OBJETIVOS").FindElement2("OBJETIVO","ID",MyITEM.Id);
		DDOITEM.SetAttr("nmd-status" , "~u,");							
		DDOITEM.SetAttr("n_resultado", MyITEM.Value==null?"":MyITEM.Value*this.MaxEscala); 
	}
}

