					PLA.Items=new Array();
PLA.AddItem = function(MyItem)
{        
	this.Items["K_"+MyItem.Id]=MyItem;
}       

PLA.GetItem = function(Id)
{        
	return this.Items["K_"+Id];
}       

PLA.DelItem = function(Id)
{              
	if (!confirm("Esta seguro que quiere Eliminarlo?")) return;

	MyIT=this.GetItem(Id);
	MyIT.Delete=true;  

	MyTR=document.getElementById("TR_O_"+Id);
	MyTR.style.display="none";

	this.RECALC();
	this.REFRESH();
}

PLA.NewItem = function()
{              
	this.Count++;        

	var ITEM=new Object();  
	ITEM.Id="N_"+this.Id+"_"+this.Count;
	ITEM.Pond=1;
	ITEM.CtrlList=null;
	ITEM.Value=null;
	ITEM.New=true;
	ITEM.Delete=false;
	this.AddItem(ITEM);

	//Agrego el ROW
	var TBL=document.getElementById("TBL_"+this.Id);
	var TR_TMP=document.getElementById("TR_OT_"+this.Id);

	var TR=TBL.insertRow(TBL.rows.length-2);
	TR.id="TR_O_"+ITEM.Id;

	for (var t=0; t!=TR_TMP.cells.length; t++)
	{                 
		var CELD=TR.insertCell();

		strHTML=TR_TMP.cells.item(t).innerHTML;
		strHTML=Replace(strHTML,"STR_REPLACE_NAME","'"+ITEM.Id+"'");
		strHTML=Replace(strHTML,"REPLACE_NAME",ITEM.Id);

		CELD.innerHTML=strHTML;
	}          

	this.RECALC();
	this.REFRESH();
}

PLA.RECALC = function()
{                
	var key, MyITEM, t, found=false;   

	this.Value=0.0;
	this.MaxValue=0.0;

	//Recorro los ITEMS
	for (key in this.Items)
	{
		MyITEM=this.Items[key];
		if (MyITEM.Delete) continue;

		MyITEM.CtrlList=document.getElementsByName("O_"+MyITEM.Id);

		//Valor
		MyITEM.Value=null;
		for(t=0; t!=MyITEM.CtrlList.length; t++)
			if (MyITEM.CtrlList.item(t).checked) 
				MyITEM.Value=parseFloat(MyITEM.CtrlList.item(t).value) / this.MaxEscala;

		//Totales      
		if (this.Value==null || MyITEM.Value==null)
		{
			this.Value   =null;
		} else
		{                       
			found=true;
			this.MaxValue+=MyITEM.Pond;
			this.Value   +=MyITEM.Pond*MyITEM.Value;
		}
	}            
	if (!found)          
		this.Value=null;
}

PLA.REFRESH = function()
{
	var CELD;

	CELD=document.getElementById("T_"+this.Id);
	CELD.innerHTML=(this.Value==null?"":Math.round(100*this.Value/this.MaxValue)+"%");
}

PLA.DDOCHANGE = function(DDOEVA, DDOPLA)
{
	var key, MyITEM, DDOITEM;   

	DDOPLA.SetAttr("nmd-status" , "~u,");
	DDOPLA.SetAttr("n_resultado", this.Value==null?"":(this.Value*this.MaxEscala/this.MaxValue));

	var MaxID=0;
	for (DDOITEM=DDOPLA.FindElement("OBJETIVOS").FirstChild(); DDOITEM!=null; DDOITEM=DDOITEM.Next())
		if	(compare(parseInt(DDOITEM.GetAttr("c_objetivo"),10),MaxID)==1) 
			MaxID=parseInt(DDOITEM.GetAttr("c_objetivo"),10);

 	for (key in this.Items)
 	{                      
 		MyITEM=this.Items[key];

 		if (MyITEM.New)
 		{                              
 			if (MyITEM.Delete) continue;

 			MaxID++;
			DDOITEM=DDOPLA.FindElement("OBJETIVOS").AddTailElement("OBJETIVO");
			DDOITEM.SetAttr("nmd-status"   , "~i,");							
			DDOITEM.SetAttr("id"           , "~"+MyITEM.Id);
			DDOITEM.SetAttr("c_objetivo"   , MaxID);
			DDOITEM.SetAttr("d_objetivo"   , document.getElementById("MSG_"+MyITEM.Id).value);
			DDOITEM.SetAttr("n_ponderacion", "1");
			DDOITEM.SetAttr("n_resultado"  , MyITEM.Value==null?"":MyITEM.Value*this.MaxEscala); 

			DDOITEM.AddTailElement("oi_competencia");
			DDOITEM.AddTailElement("oi_escala");
 		} else
 		{
			DDOITEM=DDOPLA.FindElement("OBJETIVOS").FindElement2("OBJETIVO","ID",MyITEM.Id);
			DDOITEM.SetAttr("nmd-status" , MyITEM.Delete?"~d,":"~u,");							
			DDOITEM.SetAttr("n_resultado", MyITEM.Value==null?"":MyITEM.Value*this.MaxEscala); 
 		}

	}
}

