PLA.REFRESH = function()
{ 
	var key, MyPLA, MaxValue;				

  MaxValue=0.0;                       
  Value=0.0;
	for(key in EVA.Plantillas)
	{                 
		MyPLA=EVA.Plantillas[key];
		if (!MyPLA.MostrarResumen) continue;

		MaxValue+=MyPLA.Pond;
	}        

	for(key in EVA.Plantillas)
	{                 
		MyPLA=EVA.Plantillas[key];
		if (!MyPLA.MostrarResumen) continue;

		MyOBJ=document.getElementById("R_"+MyPLA.Id);
		MyOBJ.innerHTML=(MyPLA.Value==null?"-":Math.round(100*MyPLA.Value/MyPLA.MaxValue)+"%");

		if (MyPLA.Value==null || Value==null) 
		{ 
			MyVal=null;
			Value=null;
		} else 
		{
			MyVal=MyPLA.Pond*MyPLA.Value/MyPLA.MaxValue;
			Value+=MyVal;
		}

		MyOBJ=document.getElementById("RS_"+MyPLA.Id);
		MyOBJ.innerHTML=(MyVal=null?"-":Math.round(100*MyVal/MaxValue)+"%");
	}
	MyOBJ=document.getElementById("R_TOT");
	MyOBJ.innerHTML=(Value==null?"-":Math.round(100*Value/MaxValue)+"%");
}

